        return formatInTimeZone(dateObj, timeZone || '', 'MM/dd/yyyy');
      default:
        return format(dateObj, outputFormat);
    }
  } catch (_err) {
    console.warn(`unable to parse date ${date?.toString()}`);
  }

  return 'Invalid Date';
};

